/**
 * 根据汉字查询笔顺数据
 * @param {string} charId - 汉字字符（如 '大'）或包含汉字的数据库 ID
 * @returns {Object|null} 返回笔画数据 { char, strokes } 或 null
 */
function getStrokeData(charId) {
  if (!charId) return null;
  // 直接查找
  if (STROKE_MAP[charId]) return STROKE_MAP[charId];
  // 遍历查找包含关系
  for (var key in STROKE_MAP) {
    if (STROKE_MAP.hasOwnProperty(key)) {
      if (String(charId).indexOf(key) >= 0) {
        return STROKE_MAP[key];
      }
    }
  }
  return null;
}

module.exports = {
  getStrokeData: getStrokeData
};